// src/Login.js
import React, { useState } from "react";
import { createClient } from "@supabase/supabase-js";
import { motion } from "framer-motion";
import { Loader2, Eye, EyeOff, LogIn } from "lucide-react";

const supabase = createClient(
    process.env.REACT_APP_SUPABASE_URL,
    process.env.REACT_APP_SUPABASE_KEY
);

/** --- Animated SVG Brand Logo (no images, pure code) --- */
function BrandLogo() {
    return (
        <motion.div
            className="brand-wrap"
            initial={{ opacity: 0, y: -14 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.55 }}
        >
            <svg
                className="brand-svg"
                viewBox="0 0 520 200"
                role="img"
                aria-label="Görkem Çadırcı - Software Developer"
            >
                <defs>
                    {/* Gradient & glow */}
                    <linearGradient id="g1" x1="0%" y1="0%" x2="100%" y2="0%">
                        <stop offset="0%" stopColor="#0ea5e9" />
                        <stop offset="60%" stopColor="#38bdf8" />
                        <stop offset="100%" stopColor="#22d3ee" />
                    </linearGradient>
                    <radialGradient id="glow" cx="50%" cy="50%" r="50%">
                        <stop offset="0%" stopColor="rgba(56,189,248,.45)" />
                        <stop offset="100%" stopColor="rgba(56,189,248,0)" />
                    </radialGradient>
                    <filter id="sofGlow" x="-50%" y="-50%" width="200%" height="200%">
                        <feGaussianBlur stdDeviation="8" result="b" />
                        <feMerge>
                            <feMergeNode in="b" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                    {/* Shimmer mask */}
                    <linearGradient id="shimmer" x1="0" y1="0" x2="1" y2="0">
                        <stop offset="0" stopColor="white" stopOpacity="0" />
                        <stop offset="0.5" stopColor="white" stopOpacity="0.45" />
                        <stop offset="1" stopColor="white" stopOpacity="0" />
                    </linearGradient>
                    <mask id="shine">
                        <rect width="100%" height="100%" fill="black" />
                        <motion.rect
                            x="-40%" y="0" width="40%" height="100%" fill="url(#shimmer)"
                            animate={{ x: ["-40%", "140%"] }}
                            transition={{ repeat: Infinity, duration: 3.6, ease: "easeInOut" }}
                        />
                    </mask>
                </defs>

                {/* Soft background glow */}
                <circle cx="90" cy="100" r="74" fill="url(#glow)" />

                {/* Monogram badge */}
                <g transform="translate(16,16)">
                    <circle cx="74" cy="84" r="70" fill="rgba(255,255,255,0.06)" stroke="rgba(255,255,255,0.12)" />
                    {/* G */}
                    <motion.path
                        d="M74,24 A60,60 0 1 0 134,84 L104,84"
                        fill="none"
                        stroke="url(#g1)"
                        strokeWidth="8"
                        strokeLinecap="round"
                        filter="url(#sofGlow)"
                        initial={{ pathLength: 0 }}
                        animate={{ pathLength: 1 }}
                        transition={{ duration: 1.2, ease: "easeInOut" }}
                    />
                    {/* C */}
                    <motion.path
                        d="M122,84 A48,48 0 1 1 122,84.01"
                        transform="translate(-18,0)"
                        fill="none"
                        stroke="url(#g1)"
                        strokeWidth="8"
                        strokeLinecap="round"
                        strokeDasharray="6 14"
                        initial={{ pathLength: 0, opacity: 0 }}
                        animate={{ pathLength: 1, opacity: 1 }}
                        transition={{ duration: 1.1, ease: "easeInOut", delay: 0.2 }}
                    />
                </g>

                {/* Text block */}
                <g transform="translate(190,66)" mask="url(#shine)">
                    <text x="0" y="0" fill="url(#g1)" fontSize="28" fontWeight="800" letterSpacing="0.4">
