}

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [show, setShow] = useState(false);
    const [err, setErr] = useState("");
    const [loading, setLoading] = useState(false);

    const handleLogin = async (e) => {
        e.preventDefault();
        setErr("");
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();
            if (error || !data) {
                setErr("❌ Hatalı kullanıcı adı veya şifre!");
                return;
            }
            localStorage.setItem("kullanici", JSON.stringify(data));
            // reelCreds vb. eski mantık gerekiyorsa burada ekleyebilirsin.
            onLoginSuccess?.();
        } catch (e2) {
            console.error(e2);
            setErr("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-root">
            <style>{css}</style>

            {/* Background */}
            <div className="bg">
                <div className="gradient" />
                <div className="lanes lanes-left" />
                <div className="lanes lanes-right" />
            </div>

            {/* Logo (SVG, animasyonlu) */}
            <BrandLogo />

            {/* Login Card */}
            <motion.form
                onSubmit={handleLogin}
                className="card"
                initial={{ opacity: 0, y: 18, scale: 0.98 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ duration: 0.55, ease: [0.2, 0.8, 0.2, 1] }}
            >
                <div className="card-head">
                    <LogIn size={18} />
                    <span>Giriş</span>
                </div>

                <label className="label">Kullanıcı Adı</label>
                <input
                    className="input"
                    type="text"
                    placeholder="kullanici_adi"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    autoComplete="username"
                    required
                />

                <label className="label">Şifre</label>
                <div className="pass">
                    <input
                        className="input"
                        type={show ? "text" : "password"}
                        placeholder="••••••••"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        autoComplete="current-password"
                        required
                    />
                    <button
                        type="button"
                        className="eye"
                        aria-label={show ? "Şifreyi gizle" : "Şifreyi göster"}
                        onClick={() => setShow((s) => !s)}
                    >
                        {show ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                </div>

                {err && <div className="alert">{err}</div>}

                <button className="btn" type="submit" disabled={loading}>
                    {loading ? (
                        <span className="btn-inner">
                            <Loader2 className="spin" size={16} /> Giriş yapılıyor…
                        </span>
                    ) : (
                        "Giriş"
                    )}
                </button>
            </motion.form>
        </div>
    );
}

/* ====== Minimal modern CSS (tek dosyada) ====== */
const css = `
:root{
  --bg0:#050a13;
  --bg1:#0a1324;
  --card:#0b1d38f0;
  --glass:rgba(255,255,255,.06);
  --border:rgba(255,255,255,.14);
  --text:#e8f0ff;
  --muted:#9db0c9;
  --primary:#38bdf8;
  --primary2:#0ea5e9;
  --accent:#22d3ee;
  --shadow: 0 30px 80px rgba(2,8,23,.6);
}

*{box-sizing:border-box}
html,body,#root,.login-root{height:100%}
body{margin:0;background:var(--bg0);color:var(--text);font:14px/1.45 Inter, ui-sans-serif, system-ui}

.login-root{
  display:grid; place-items:center; gap:24px;
  padding: clamp(16px, 3vw, 36px); position:relative; overflow:hidden;
}

/* BG */
.bg{position:absolute; inset:0; z-index:0; overflow:hidden}
.gradient{
  position:absolute; inset:0;
  background:
    radial-gradient(900px 600px at 110% -10%, rgba(56,189,248,.25), transparent 60%),
    radial-gradient(800px 500px at -5% 110%, rgba(34,211,238,.18), transparent 55%),
    linear-gradient(180deg, var(--bg0), var(--bg1));
  animation:hue 18s ease-in-out infinite alternate;
  filter:saturate(120%);
}
@keyframes hue { from{ filter:hue-rotate(0deg) } to{ filter:hue-rotate(12deg) } }
.lanes{
  position:absolute; top:50%; width:320px; height:160%;
  filter: blur(18px); opacity:.6; pointer-events:none;
  background: linear-gradient(to bottom, rgba(255,255,255,.1), rgba(255,255,255,.04), transparent);
}
.lanes-left{ left:-80px; transform:translateY(-50%) rotate(18deg) }
.lanes-right{ right:-80px; transform:translateY(-50%) rotate(-18deg);
  background: linear-gradient(to bottom, rgba(56,189,248,.12), rgba(14,165,233,.08), transparent);
}

/* Brand */
.brand-wrap{ position:relative; z-index:1; width:min(940px,95vw) }
.brand-svg{ width:100%; height:auto; display:block; }

/* Card */
.card{
  position:relative; z-index:1;
  width:min(440px, 92vw); padding:20px;
  border-radius:20px; background:var(--card);
  border:1px solid var(--border); box-shadow:var(--shadow);
  display:grid; gap:12px;
}
.card-head{ display:flex; align-items:center; gap:8px; font-weight:800; margin-bottom:6px; }

.label{ font-size:12px; color:#cfe0ff; }
.input{
  width:100%; border:1px solid var(--border); border-radius:12px;
  background:var(--glass); color:var(--text);
  padding:12px 14px; outline:none; transition:border-color .2s, box-shadow .2s;
}
.input:focus{
  border-color: rgba(56,189,248,.55);
  box-shadow:0 0 0 5px rgba(56,189,248,.16);
}
.pass{ position:relative }
.eye{
  position:absolute; right:10px; top:50%; transform:translateY(-50%);
  border:0; background:transparent; color:#d0def7; cursor:pointer; padding:4px;
}
.eye:hover{ color:#fff }

/* Alert */
.alert{
  background: rgba(239,68,68,.12);
  border:1px solid rgba(239,68,68,.35);
  color:#ffd6d6; border-radius: 12px; padding:10px 12px; font-size:13px;
}

/* Button */
.btn{
  width:100%; border:0; border-radius:14px;
  background: linear-gradient(100deg, var(--primary2), var(--primary) 60%, var(--accent));
  color:white; font-weight:800; letter-spacing:.2px;
  padding: 12px 14px; cursor:pointer;
  box-shadow: 0 12px 40px rgba(14,165,233,.25);
  transition: filter .2s, transform .06s;
}
.btn:hover{ filter: brightness(1.06) }
.btn:active{ transform: translateY(1px) }
.btn:disabled{ opacity:.7; cursor:not-allowed }
.btn-inner{ display:inline-flex; gap:10px; align-items:center }
.spin{ animation:spin 1s linear infinite }
@keyframes spin{ to{ transform: rotate(360deg) } }
`;
